class Node:
    __slots__ = ('l', 'r')
    def __init__(self, l, r):
        self.l = l
        self.r = r

def add_line(node, new_line):
    L, R = node.l, node.r
    mid = (L + R) // 2
    cur = node.line
    if cur is None:
        node.line = new_line
        return
    if eval_line(new_line, mid) > eval_line(cur, mid):
        node.line, new_line = new_line, cur
        cur = node.line
    if L == R:
        return
    if eval_line(new_line, L) > eval_line(node.line, L):
        if node.left is None:
            node.left = Node(L, mid)
        add_line(node.left, new_line)
    elif eval_line(new_line, R) > eval_line(node.line, R):
        if node.right is None:
            node.right = Node(mid + 1, R)
        add_line(node.right, new_line)

